let handlersRegistered = false;

function registerIPCHandlers() {
  if (handlersRegistered) {
    console.warn('[IPC] Handlers already registered, skipping');
    return;
  }

  // 使用 handleOnce 的替代：先移除再注册
  const channels = Object.values(IPC_CHANNELS);
  for (const channel of channels) {
    ipcMain.removeHandler(channel);
    ipcMain.removeAllListeners(channel);
  }

  // 注册 invoke handlers（请求-响应模式）
  ipcMain.handle(IPC_CHANNELS.NOTE_CREATE, async (_event, data) => db.createNote(data));
  ipcMain.handle(IPC_CHANNELS.NOTE_UPDATE, async (_event, id, data) => db.updateNote(id, data));
  ipcMain.handle(IPC_CHANNELS.NOTE_DELETE, async (_event, id) => db.deleteNote(id));
  ipcMain.handle(IPC_CHANNELS.NOTE_GET, async (_event, id) => db.getNote(id));
  ipcMain.handle(IPC_CHANNELS.NOTE_LIST, async (_event, filter) => db.listNotes(filter));
  ipcMain.handle(IPC_CHANNELS.NOTEBOOK_CREATE, async (_event, data) => db.createNotebook(data));
  ipcMain.handle(IPC_CHANNELS.NOTEBOOK_LIST, async () => db.listNotebooks());
  ipcMain.handle(IPC_CHANNELS.TAG_LIST, async () => db.listTags());
  ipcMain.handle(IPC_CHANNELS.TAG_CREATE, async (_event, name, color) => db.createTag(name, color));
  ipcMain.handle(IPC_CHANNELS.SEARCH_FULLTEXT, async (_event, query) => db.searchFulltext(query));

  // 注册 send handlers（单向消息）— 用 on 代替 handle
  ipcMain.on(IPC_CHANNELS.WINDOW_MINIMIZE, () => windowManager.minimize());
  ipcMain.on(IPC_CHANNELS.WINDOW_MAXIMIZE, () => windowManager.maximize());
  ipcMain.on(IPC_CHANNELS.WINDOW_CLOSE, () => windowManager.close());

  handlersRegistered = true;
  console.log(`[IPC] ${channels.length} handlers registered`);
}

// 应用退出时清理
app.on('will-quit', () => {
  const channels = Object.values(IPC_CHANNELS);
  for (const channel of channels) {
    ipcMain.removeHandler(channel);
    ipcMain.removeAllListeners(channel);
