import { useState, useEffect, useRef } from 'react';

const useWebSocketWithReconnection = (url, protocols, options = {}) => {
  const [socket, setSocket] = useState(null);
  const [isConnected, setIsConnected] = useState(false);
  const retryCount = useRef(0);
  const maxRetries = options.maxRetries || 10;

  const connect = () => {
    const ws = new WebSocket(url, protocols);

    ws.onopen = () => {
      setIsConnected(true);
      retryCount.current = 0;
      console.log('WebSocket connected');
    };

    ws.onclose = () => {
      setIsConnected(false);
      console.log('WebSocket closed. Attempting to reconnect...');
      if (retryCount.current < maxRetries) {
        retryCount.current++;
        const reconnectDelay = Math.min(1000 * Math.pow(2, retryCount.current), 30000);
        setTimeout(connect, reconnectDelay);
      } else {
        console.error('Max reconnection attempts reached.');
      }
    };

    ws.onerror = (error) => {
      console.error('WebSocket error:', error);
    };

    setSocket(ws);
  };

  useEffect(() => {
    connect();
    return () => socket?.close(); // Cleanup on unmount
  }, []);

  return { socket, isConnected };
};

export default useWebSocketWithReconnection;
```
In this example:
- The `connect` function initializes the WebSocket, and `onclose` contains the reconnection logic with exponential backoff.
- The `retryCount` keeps track of how many reconnect attempts have been made, and `maxRetries` limits the number of retries.
- The component that uses this hook can access `socket` and `isConnected` to manage its state accordingly.

