1. **Add a `reconnect` function**:
```javascript
const useWebSocketWithReconnection = (url, protocols, options = {}) => {
  const [socket, setSocket] = useState(null);
  const [isConnected, setIsConnected] = useState(false);
  const [isOnline, setIsOnline] = useState(true);
  const retryCount = useRef(0);
  const maxRetries = options.maxRetries || 10;

  useEffect(() => {
    const unsubscribe = NetInfo.addEventListener((state) => {
      setIsOnline(state.isConnected);
    });

    return () => unsubscribe();
  }, []);

  const connect = () => {
    const ws = new WebSocket(url, protocols);

    ws.onopen = () => {
      setIsConnected(true);
      retryCount.current = 0;
      console.log('WebSocket connected');
    };

    ws.onclose = () => {
      setIsConnected(false);
      if (isOnline && retryCount.current < maxRetries) {
        retryCount.current++;
        const reconnectDelay = Math.min(1000 * Math.pow(2, retryCount.current), 30000);
        setTimeout(connect, reconnectDelay);
      }
    };

    ws.onerror = (error) => {
      console.error('WebSocket error:', error);
    };

    setSocket(ws);
  };

  const reconnect = () => {
    console.log('Manual reconnection triggered');
    if (socket) {
      socket.close();
    }
    connect();
  };

  useEffect(() => {
    if (isOnline) {
      connect();
    }

    return () => socket?.close();
  }, [isOnline]);

  return { socket, isConnected, isOnline, reconnect };
};
```

2. **Use the `reconnect` function in your component**:
```javascript
import React from 'react';
import { Button, Text, View } from 'react-native';
import useWebSocketWithReconnection from './useWebSocketWithReconnection';

const MyApp = () => {
  const { socket, isConnected, isOnline, reconnect } = useWebSocketWithReconnection('wss://example.com/socket');

  return (
    <View style={{ padding: 20 }}>
      <Text>Connection Status: {isConnected ? 'Connected' : 'Disconnected'}</Text>
      <Text>Network Status: {isOnline ? 'Online' : 'Offline'}</Text>
      <Button title="Reconnect" onPress={reconnect} disabled={!isOnline} />
    </View>
  );
};

export default MyApp;
```

### Explanation:
- The `reconnect` function closes the current WebSocket (if any) and triggers a new connection.
- The `Reconnect` button calls this function when pressed. It’s disabled if the network is offline to prevent unnecessary actions.

