### Step 2: Add Command
Create an `add.go` file in the `cmd` folder for adding credentials.

```go
package cmd

import (
	"fmt"
	"mycli/config"

	"github.com/spf13/cobra"
)

var (
	name   string
	env    string
	key    string
)

var addCmd = &cobra.Command{
	Use:   "add",
	Short: "Add API credentials",
	Long:  "Adds a new set of API credentials to the YAML configuration file.",
	Run: func(cmd *cobra.Command, args []string) {
		credential := map[string]string{
			"name": name,
			"env":  env,
			"key":  key,
		}
		if err := config.AddCredential(credential); err != nil {
			fmt.Println("Error adding credential:", err)
			return
		}
		fmt.Println("Credential added successfully!")
	},
}

func init() {
	rootCmd.AddCommand(addCmd)
	addCmd.Flags().StringVarP(&name, "name", "n", "", "Name of the API")
	addCmd.Flags().StringVarP(&env, "env", "e", "", "Environment (e.g., dev, prod)")
	addCmd.Flags().StringVarP(&key, "key", "k", "", "API key or secret")

	addCmd.MarkFlagRequired("name")
	addCmd.MarkFlagRequired("env")
	addCmd.MarkFlagRequired("key")
}
