Great question! Robust error handling is critical for a good user experience. Here are some improvements you can make:

### Update `AddCredential` in `config.go`
Handle cases where the YAML file is missing or corrupted:

```go
package config

import (
	"errors"
	"gopkg.in/yaml.v3"
	"os"
)

const configFile = "credentials.yaml"

func AddCredential(credential map[string]string) error {
	var credentials []map[string]string

	// Check if file exists
	if _, err := os.Stat(configFile); errors.Is(err, os.ErrNotExist) {
		credentials = []map[string]string{} // Initialize empty credentials if file doesn't exist
	} else {
		file, err := os.ReadFile(configFile)
		if err != nil {
			return errors.New("could not read configuration file")
		}
		if err := yaml.Unmarshal(file, &credentials); err != nil {
			return errors.New("invalid YAML format in configuration file")
		}
	}

	credentials = append(credentials, credential)
	data, err := yaml.Marshal(&credentials)
	if err != nil {
		return errors.New("failed to marshal credentials")
	}

	if err := os.WriteFile(configFile, data, 0644); err != nil {
		return errors.New("failed to write to configuration file")
	}

	return nil
}
```

### Update `ListCredentials`
Add error handling for missing or corrupted YAML files:

```go
func ListCredentials() ([]map[string]string, error) {
	var credentials []map[string]string

	file, err := os.ReadFile(configFile)
	if errors.Is(err, os.ErrNotExist) {
		return nil, errors.New("no credentials found; YAML file is missing")
	} else if err != nil {
		return nil, errors.New("could not read configuration file")
	}

	err = yaml.Unmarshal(file, &credentials)
	if err != nil {
		return nil, errors.New("invalid YAML format in configuration file")
	}

	return credentials, nil
}
