import FlexSearch from 'flexsearch';

let index = new FlexSearch({
  tokenize: 'forward',
  threshold: 0,
});

const docs = [
  { id: 1, title: 'Introduction', content: 'This is the introduction to your project.' },
  { id: 2, title: 'Installation', content: 'Steps to install your project.' },
  // Add more content dynamically
];

// Add all documents to the index
