### Step 5: Create Category Pages
You can dynamically generate category pages using `getStaticPaths` and `getStaticProps` in your Next.js pages:
```javascript
// pages/docs/[category].js
import fs from 'fs';
import path from 'path';
import matter from 'gray-matter';

export async function getStaticPaths() {
  const categories = fs.readdirSync(path.join(process.cwd(), 'docs'));
  const paths = categories.map((category) => ({ params: { category } }));

  return { paths, fallback: false };
}

export async function getStaticProps({ params }) {
  const docsPath = path.join(process.cwd(), 'docs', params.category);
  const filenames = fs.readdirSync(docsPath);

  const docs = filenames.map((filename) => {
    const filePath = path.join(docsPath, filename);
    const fileContent = fs.readFileSync(filePath, 'utf-8');
    const { data, content } = matter(fileContent);

    return { meta: data, content };
  });

  return { props: { docs } };
}

export default function CategoryPage({ docs }) {
  return (
    <div className="prose mx-auto">
      {docs.map((doc) => (
        <div key={doc.meta.title}>
          <h2>{doc.meta.title}</h2>
          <p>{doc.content.slice(0, 100)}...</p>
        </div>
      ))}
    </div>
  );
}
```

