To make the search persistent, you can use React's context or the browser's local storage. Context is better for app-wide state management, while local storage ensures persistence even after a page reload. Here's how you can implement both approaches:

### Option 1: Using React Context for Persistent State
Create a `SearchContext` to store and manage the search state globally:
```javascript
// context/SearchContext.js
import React, { createContext, useState, useContext } from 'react';

const SearchContext = createContext();

export function SearchProvider({ children }) {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState([]);

  const updateSearch = (newQuery) => {
    setQuery(newQuery);
    // Call the search utility to get the results
    const searchResults = search(newQuery);
    setResults(searchResults);
  };

  return (
    <SearchContext.Provider value={{ query, results, updateSearch }}>
      {children}
    </SearchContext.Provider>
  );
}

export function useSearchContext() {
  return useContext(SearchContext);
}
```

Wrap your app in the `SearchProvider` in `pages/_app.js`:
```javascript
import { SearchProvider } from '../context/SearchContext';

export default function MyApp({ Component, pageProps }) {
  return (
    <SearchProvider>
      <Component {...pageProps} />
    </SearchProvider>
  );
}
```

Then, update the `SearchBar` component to use the context:
```javascript
// components/SearchBar.js
import React from 'react';
import { useSearchContext } from '../context/SearchContext';

export default function SearchBar() {
  const { query, results, updateSearch } = useSearchContext();

  const handleSearch = (event) => {
    updateSearch(event.target.value);
  };

  return (
