            <li
              key={result.id}
              className="p-2 border-b hover:bg-gray-200 cursor-pointer"
            >
              {result.title}
            </li>
          ))}
        </ul>
      )}
    </div>
  );
}
```
Now your search state will persist across different pages as long as the user doesn't reload the browser.

### Option 2: Using Local Storage
To persist search state even after a page reload, store the query and results in `localStorage`:

Update `SearchBar` as follows:
```javascript
import React, { useState, useEffect } from 'react';
import { search } from '../utils/search';

export default function SearchBar() {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState([]);

  useEffect(() => {
    const savedQuery = localStorage.getItem('searchQuery');
    const savedResults = JSON.parse(localStorage.getItem('searchResults'));

    if (savedQuery) setQuery(savedQuery);
    if (savedResults) setResults(savedResults);
  }, []);

  const handleSearch = (event) => {
    const newQuery = event.target.value;
    setQuery(newQuery);
    localStorage.setItem('searchQuery', newQuery);

    const searchResults = search(newQuery);
    setResults(searchResults);
    localStorage.setItem('searchResults', JSON.stringify(searchResults));
  };

  return (
    <div className="relative w-full max-w-md mx-auto">
      <input
        type="text"
        value={query}
        onChange={handleSearch}
        placeholder="Search documentation..."
        className="w-full p-2 border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary"
      />
      {results.length > 0 && (
        <ul className="absolute mt-2 bg-white border rounded-lg shadow-lg">
          {results.map((result) => (
            <li
              key={result.id}
              className="p-2 border-b hover:bg-gray-200 cursor-pointer"
            >
              {result.title}
            </li>
          ))}
        </ul>
      )}
    </div>
  );
}
```

### Comparing the Two Methods
- **React Context** is ideal for app-wide state management but doesn't persist across page reloads.
- **Local Storage** persists the search state even if the page is refreshed but requires manual cleanup (e.g., clearing local storage when it's no longer needed).

Both approaches are valid depending on your needs. Let me know if you'd like help integrating anything!

Sure! Setting up Nginx as a reverse proxy with SSL termination involves a few steps. First, you'll need an SSL certificate. You can get one for free from Let's Encrypt or purchase one from a certificate authority. Once you have the certificate and the key, you can configure Nginx. Here's an example configuration:

```nginx
server {
    listen 443 ssl;
    server_name yourdomain.com;

    ssl_certificate /path/to/your/certificate.crt;
    ssl_certificate_key /path/to/your/private.key;

    ssl_protocols TLSv1.2 TLSv1.3;
    ssl_ciphers HIGH:!aNULL:!MD5;
    ssl_prefer_server_ciphers on;

    location / {
        proxy_pass http://your_internal_app;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
    }
}

server {
    listen 80;
    server_name yourdomain.com;
    return 301 https://$host$request_uri;
}
```

The first server block handles HTTPS requests and terminates SSL. The second server block redirects HTTP requests to HTTPS. Adjust the paths to your SSL certificate and private key, and replace `your_internal_app` with the actual address of your backend service. Want more details or troubleshooting tips?

To ensure your SSL setup is secure and aligns with best practices, here are some specific steps:

1. **Use Strong SSL/TLS Protocols**: Disable older protocols like SSLv3 and TLSv1. For Nginx, you should ideally enable only TLSv1.2 and TLSv1.3:
   ```nginx
   ssl_protocols TLSv1.2 TLSv1.3;
   ```

2. **Choose Secure Ciphers**: Use a secure list of ciphers while excluding weak ones. This provides strong encryption:
   ```nginx
   ssl_ciphers HIGH:!aNULL:!MD5;
   ssl_prefer_server_ciphers on;
   ```

3. **Enable HTTP Strict Transport Security (HSTS)**: This forces browsers to use HTTPS and prevents downgrade attacks:
   ```nginx
   add_header Strict-Transport-Security "max-age=31536000; includeSubDomains";
   ```
   Be cautious: once you enable this, it can’t be undone easily for your visitors without adjusting browser caches.

4. **Use OCSP Stapling**: This improves the performance of SSL handshakes by providing certificate status directly:
   ```nginx
   ssl_stapling on;
   ssl_stapling_verify on;
   resolver 8.8.8.8 8.8.4.4 valid=300s;
   resolver_timeout 5s;
   ```

5. **Test Your Setup**: Use tools like [SSL Labs](https://www.ssllabs.com/ssltest/) to analyze your server's SSL configuration. It provides a detailed report and rating (A+ is ideal).

6. **Keep Nginx and OpenSSL Updated**: Regularly update Nginx and OpenSSL to ensure you have the latest security fixes and features.

By following these steps, you’ll have a robust SSL configuration for your reverse proxy. Let me know if you need help implementing any of these!

