### Step 1: Access the App Data Directory
Tauri provides a helper function to get the app’s local data directory. To use it, update your `src-tauri/src/main.rs` file to dynamically determine the database’s path:

```rust
use tauri::api::path::app_local_data_dir;
use std::path::PathBuf;

#[tokio::main]
async fn main() {
    // Get the app's local data directory
    let data_dir: PathBuf = app_local_data_dir()
        .expect("Failed to resolve app data directory");

    // Ensure the directory exists
    std::fs::create_dir_all(&data_dir).expect("Failed to create app data directory");

    // Define the path for the database file
    let db_path = data_dir.join("app.db");

    // Connect to the database
    let pool = SqlitePoolOptions::new()
        .max_connections(5)
        .connect(&format!("sqlite:{}", db_path.to_string_lossy()))
        .await
