  try {
    await invoke('reset_database');
    alert('Database reset successfully!');
  } catch (error) {
    console.error('Failed to reset database:', error);
  }
}

return (
  <div>
    {/* Add this button for testing purposes */}
    <button onClick={resetDatabase}>Reset Database</button>
  </div>
