   <template>
     <v-container>
       <v-row>
         <v-col cols="12">
           <v-text-field v-model="newTaskTitle" label="New Task" outlined dense></v-text-field>
           <v-btn color="primary" @click="addTask">Add Task</v-btn>
         </v-col>
       </v-row>

       <v-row>
         <v-col cols="12" v-for="task in tasks" :key="task.id">
           <v-card class="mb-2">
             <v-card-title>
               <v-checkbox v-model="task.completed" @change="updateTask(task)"></v-checkbox>
               <span :class="{ 'line-through': task.completed }">{{ task.title }}</span>
             </v-card-title>
             <v-card-actions>
               <v-btn color="error" text small @click="deleteTask(task.id)">Delete</v-btn>
             </v-card-actions>
           </v-card>
         </v-col>
       </v-row>
     </v-container>
   </template>

   <script>
   import { db } from "@/firebase";

   export default {
     data() {
       return {
         newTaskTitle: "",
         tasks: []
       };
     },
     created() {
       this.fetchTasks();
     },
     methods: {
       async fetchTasks() {
         db.collection("tasks").orderBy("createdAt", "desc").onSnapshot((snapshot) => {
           this.tasks = snapshot.docs.map(doc => ({
             id: doc.id,
             ...doc.data()
           }));
         });
       },
       async addTask() {
         if (this.newTaskTitle.trim() === "") return;
         await db.collection("tasks").add({
           title: this.newTaskTitle,
           completed: false,
           createdAt: firebase.firestore.FieldValue.serverTimestamp()
         });
         this.newTaskTitle = "";
       },
       async updateTask(task) {
         await db.collection("tasks").doc(task.id).update({
           completed: task.completed
         });
       },
       async deleteTask(taskId) {
         await db.collection("tasks").doc(taskId).delete();
       }
     }
   };
   </script>

   <style>
   .line-through {
     text-decoration: line-through;
   }
   </style>
   ```

4. **Explanation**
   - **Real-time updates:** Firestore’s `onSnapshot` allows you to listen to changes in the `tasks` collection and automatically updates the `tasks` array in real-time.
   - **Adding tasks:** The `addTask` method adds a new document to the `tasks` collection with a title, a `completed` status, and a server timestamp.
   - **Updating tasks:** The `updateTask` method updates the `completed` status of the selected task in Firestore.
   - **Deleting tasks:** The `deleteTask` method removes a task document from Firestore.

