Great question! To make the database connection reusable across commands, you can use a shared connection pool. Here’s how you can achieve that:

### Steps to Use a Shared Database Connection Pool

1. **Modify the `db.go` Helper**:
   Instead of opening and closing the connection in each command, you can create a global connection pool that persists across commands.
   ```go
   package db

   import (
       "database/sql"
       "fmt"
       "sync"
       _ "github.com/lib/pq" // PostgreSQL driver
       "usermanager/config"
   )

   var (
       dbInstance *sql.DB
       once       sync.Once
   )

   func InitDatabase(cfg *config.Config) (*sql.DB, error) {
       var err error
       once.Do(func() {
           dsn := fmt.Sprintf(
               "host=%s port=%d user=%s password=%s dbname=%s sslmode=disable",
               cfg.DB.Host, cfg.DB.Port, cfg.DB.User, cfg.DB.Password, cfg.DB.Name,
           )
           dbInstance, err = sql.Open("postgres", dsn)
           if err != nil {
               return
           }
           // Optionally set connection pool settings
           dbInstance.SetMaxOpenConns(10)
           dbInstance.SetMaxIdleConns(5)
       })
       return dbInstance, err
   }

   func GetDatabase() (*sql.DB, error) {
       if dbInstance == nil {
           return nil, fmt.Errorf("Database not initialized")
       }
       return dbInstance, nil
   }
   ```

   - `InitDatabase(cfg)`: Initializes the database connection and ensures it’s created only once using the `sync.Once` pattern.
   - `GetDatabase()`: Returns the shared connection pool.

2. **Update `main.go` to Initialize the Database**:
   You only need to initialize the database once when the CLI starts:
   ```go
   package main

   import (
       "fmt"
       "log"
       "usermanager/config"
       "usermanager/db"
       "usermanager/cmd"
   )

   func main() {
       cfg, err := config.LoadConfig("config.yaml")
       if err != nil {
           log.Fatalf("Error loading config: %v", err)
       }

       // Initialize the database connection pool
       _, err = db.InitDatabase(cfg)
       if err != nil {
           log.Fatalf("Error initializing database: %v", err)
       }

       fmt.Println("Database connection initialized!")
       cmd.Execute()
   }
   ```

3. **Update Commands to Use the Shared Connection**:
   In your commands, use the shared connection pool:

   - **Add Command** (`cmd/add.go`):
     ```go
     package cmd

     import (
         "fmt"
         "usermanager/db"
         "github.com/spf13/cobra"
     )

     var addCmd = &cobra.Command{
         Use:   "add",
         Short: "Add a user profile",
         Run: func(cmd *cobra.Command, args []string) {
             if len(args) < 2 {
                 fmt.Println("Usage: add <name> <email>")
                 return
             }

             name := args[0]
             email := args[1]

             // Get the shared database connection
             dbConn, err := db.GetDatabase()
             if err != nil {
                 fmt.Printf("Error getting database connection: %v\n", err)
                 return
             }

             // Insert the user profile into the database
             _, err = dbConn.Exec("INSERT INTO users (name, email) VALUES ($1, $2)", name, email)
             if err != nil {
                 fmt.Printf("Error adding user: %v\n", err)
                 return
             }

             fmt.Println("User added successfully!")
         },
     }

     func init() {
         rootCmd.AddCommand(addCmd)
     }
     ```

   - **View Command** (`cmd/view.go`):
     ```go
     package cmd

