```javascript
// Generate a secure random string for code_verifier
function generateCodeVerifier() {
    const array = new Uint8Array(128); // Length between 43-128 characters
    window.crypto.getRandomValues(array);
    return btoa(String.fromCharCode.apply(null, array))
        .replace(/\+/g, '-')
        .replace(/\//g, '_')
        .replace(/=+/g, '');
}

// Generate code_challenge from code_verifier
async function generateCodeChallenge(codeVerifier) {
    const encoder = new TextEncoder();
    const data = encoder.encode(codeVerifier);
    const digest = await crypto.subtle.digest('SHA-256', data);
    return btoa(String.fromCharCode(...new Uint8Array(digest)))
        .replace(/\+/g, '-')
        .replace(/\//g, '_')
        .replace(/=+/g, '');
}

// Example usage
(async () => {
    const codeVerifier = generateCodeVerifier();
    const codeChallenge = await generateCodeChallenge(codeVerifier);

    console.log('Code Verifier:', codeVerifier);
    console.log('Code Challenge:', codeChallenge);
})();
```

This example uses the browser's `crypto` APIs to generate a secure random string for the `code_verifier` and computes the SHA256 hash for the `code_challenge`. You’ll need to ensure that the server supports the PKCE flow and specify `code_challenge_method=S256` when making the authorization request.

