Absolutely! Here's how you can generate the `code_verifier` and `code_challenge` in Swift:

```swift
import Foundation
import CommonCrypto

// Function to generate a secure random code verifier
func generateCodeVerifier() -> String {
    var data = Data(count: 32) // Adjust length as needed (minimum 43, maximum 128 characters)
    let result = data.withUnsafeMutableBytes { bytes -> Int32 in
        SecRandomCopyBytes(kSecRandomDefault, data.count, bytes.baseAddress!)
    }

    guard result == errSecSuccess else {
        fatalError("Failed to generate secure random bytes")
    }

    let base64String = data.base64EncodedString()
        .replacingOccurrences(of: "+", with: "-")
        .replacingOccurrences(of: "/", with: "_")
        .replacingOccurrences(of: "=", with: "")

    return base64String
}

// Function to generate code challenge from code verifier
func generateCodeChallenge(from codeVerifier: String) -> String {
    guard let data = codeVerifier.data(using: .utf8) else {
        fatalError("Failed to convert code verifier to data")
    }

    var digest = Data(count: Int(CC_SHA256_DIGEST_LENGTH))
    _ = digest.withUnsafeMutableBytes { digestBytes -> UInt8 in
        data.withUnsafeBytes { dataBytes -> UInt8 in
            CC_SHA256(dataBytes.baseAddress, CC_LONG(data.count), digestBytes.bindMemory(to: UInt8.self).baseAddress)
        }
    }

    let base64String = digest.base64EncodedString()
        .replacingOccurrences(of: "+", with: "-")
        .replacingOccurrences(of: "/", with: "_")
        .replacingOccurrences(of: "=", with: "")

    return base64String
}

// Example usage
let codeVerifier = generateCodeVerifier()
let codeChallenge = generateCodeChallenge(from: codeVerifier)

print("Code Verifier: \(codeVerifier)")
print("Code Challenge: \(codeChallenge)")
```

This Swift implementation uses the `SecRandomCopyBytes` function to generate a secure random `code_verifier`, and computes the `code_challenge` using SHA256 hashing provided by the `CommonCrypto` library. The resulting strings are base64 URL-safe encoded by replacing special characters to conform to the PKCE standard.

