// db.js
const { Pool } = require('pg');

// Create a connection pool to the PostgreSQL database
const pool = new Pool({
  host: process.env.DATABASE_HOST || 'localhost',
  port: process.env.DATABASE_PORT || 5432,
  user: process.env.DATABASE_USER || 'postgres',
  password: process.env.DATABASE_PASSWORD || 'example',
  database: process.env.DATABASE_NAME || 'my_database'
});

// Export the pool so it can be used in other parts of the app
module.exports = {
  query: (text, params) => pool.query(text, params),
};
```

Now, in your main application file (e.g., `index.js`), you can use the `query` method to interact with the database:

```javascript
// index.js
