Absolutely! A URL shortening service is a great project that fits well with Express.js, SQLite, and JWT. Here's an outline of how you can structure it along with code snippets to get started:

### 1. **Project Setup**
First, set up your project with necessary dependencies:
```bash
mkdir url-shortener
cd url-shortener
npm init -y
npm install express sqlite3 jsonwebtoken body-parser nanoid dotenv
```
Here’s what the packages are for:
- `express`: For the web server.
- `sqlite3`: For the SQLite database.
- `jsonwebtoken`: For JWT authentication.
- `body-parser`: To parse JSON in incoming requests.
- `nanoid`: To generate unique short IDs for the URLs.
- `dotenv`: For environment variables.

### 2. **Create the Database**
Use SQLite to store the original URLs, short URLs, and metadata like creation timestamps. Create a file `db.js` for your database setup:
```javascript
const sqlite3 = require('sqlite3').verbose();
const db = new sqlite3.Database('./url_shortener.db');

// Initialize database tables
db.serialize(() => {
  db.run(`CREATE TABLE IF NOT EXISTS urls (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    short_url TEXT UNIQUE,
    original_url TEXT NOT NULL,
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP
  )`);
});

module.exports = db;
```

### 3. **Build Your Express App**
Create your main server file `index.js`:
```javascript
require('dotenv').config();
const express = require('express');
const bodyParser = require('body-parser');
const db = require('./db');
const { nanoid } = require('nanoid');
const jwt = require('jsonwebtoken');

const app = express();
const PORT = process.env.PORT || 3000;
const SECRET_KEY = process.env.JWT_SECRET || 'your_secret_key';

// Middleware
app.use(bodyParser.json());

// Route to shorten a URL
app.post('/shorten', (req, res) => {
  const { url } = req.body;

  if (!url) {
    return res.status(400).json({ error: 'URL is required' });
  }

  const shortUrl = nanoid(7); // Generate a short unique ID

  db.run(
    'INSERT INTO urls (short_url, original_url) VALUES (?, ?)',
    [shortUrl, url],
    function (err) {
      if (err) {
        return res.status(500).json({ error: 'Database error' });
      }
      res.json({ shortUrl });
    }
  );
});

// Route to resolve a short URL
app.get('/:shortUrl', (req, res) => {
  const { shortUrl } = req.params;

  db.get('SELECT original_url FROM urls WHERE short_url = ?', [shortUrl], (err, row) => {
    if (err) {
      return res.status(500).json({ error: 'Database error' });
    }

    if (row) {
      res.redirect(row.original_url); // Redirect to the original URL
    } else {
      res.status(404).json({ error: 'URL not found' });
    }
  });
});

// JWT-protected stats route
app.get('/stats', (req, res) => {
  const token = req.headers.authorization?.split(' ')[1];

  if (!token) {
    return res.status(401).json({ error: 'Missing token' });
  }

  jwt.verify(token, SECRET_KEY, (err, decoded) => {
    if (err) {
      return res.status(403).json({ error: 'Invalid token' });
    }

    db.all('SELECT * FROM urls', [], (err, rows) => {
      if (err) {
        return res.status(500).json({ error: 'Database error' });
      }

      res.json({ urls: rows });
    });
  });
});

// Generate a JWT for admin access
app.post('/login', (req, res) => {
  const { username, password } = req.body;

  // This is a simple example, replace with proper authentication logic
  if (username === 'admin' && password === 'password') {
    const token = jwt.sign({ user: username }, SECRET_KEY, { expiresIn: '1h' });
    res.json({ token });
  } else {
    res.status(403).json({ error: 'Invalid credentials' });
  }
});

app.listen(PORT, () => {
  console.log(`Server running on http://localhost:${PORT}`);
});
```

### 4. **Environment Variables**
Create a `.env` file to store your secret key:
```
JWT_SECRET=your_secret_key
PORT=3000
```

### 5. **Testing Your Service**
- Use Postman or curl to test the API endpoints:
  - `POST /shorten` with `{ "url": "https://example.com" }` to create a short URL.
  - `GET /:shortUrl` to resolve the short URL.
  - `POST /login` to get a JWT token.
  - `GET /stats` with the `Authorization: Bearer <token>` header to view URL stats.

